import akka.actor.ActorSystem
import akka.http.scaladsl.Http
import akka.http.scaladsl.model._
import akka.http.scaladsl.server.Directives._
import akka.http.scaladsl.marshallers.sprayjson.SprayJsonSupport._
import akka.http.scaladsl.unmarshalling.Unmarshal
import akka.stream.Materializer
import spray.json._

import scala.concurrent.{ExecutionContextExecutor, Future}
import scala.util.{Failure, Success}

// JSON protocol for request/response
case class FetchRequest(url: String, method: Option[String], headers: Option[Map[String, String]], body: Option[String])
case class FetchResponse(status: Int, contentType: String, body: String, success: Boolean, error: Option[String])

object JsonProtocol extends DefaultJsonProtocol {
  implicit val fetchRequestFormat: RootJsonFormat[FetchRequest] = jsonFormat4(FetchRequest)
  implicit val fetchResponseFormat: RootJsonFormat[FetchResponse] = jsonFormat5(FetchResponse)
}

object WebhookProxyService extends App {

  implicit val system: ActorSystem = ActorSystem("webhook-proxy")
  implicit val materializer: Materializer = Materializer(system)
  implicit val executionContext: ExecutionContextExecutor = system.dispatcher

  import JsonProtocol._

  def fetchUrl(fetchRequest: FetchRequest): Future[FetchResponse] = {
    val userUrl = fetchRequest.url

    val method = fetchRequest.method.getOrElse("GET").toUpperCase match {
      case "GET"    => HttpMethods.GET
      case "POST"   => HttpMethods.POST
      case "PUT"    => HttpMethods.PUT
      case "DELETE" => HttpMethods.DELETE
      case "PATCH"  => HttpMethods.PATCH
      case "HEAD"   => HttpMethods.HEAD
      case _        => HttpMethods.GET
    }

    val customHeaders: List[HttpHeader] = fetchRequest.headers.getOrElse(Map.empty).map {
      case (name, value) => HttpHeader.parse(name, value) match {
        case HttpHeader.ParsingResult.Ok(header, _) => Some(header)
        case _ => None
      }
    }.flatten.toList

    val entity = fetchRequest.body match {
      case Some(b) => HttpEntity(ContentTypes.`application/json`, b)
      case None    => HttpEntity.Empty
    }

    val httpRequest = HttpRequest(
      method = method,
      uri = userUrl,
      headers = customHeaders,
      entity = entity
    )

    Http().singleRequest(httpRequest).flatMap { response =>
      Unmarshal(response.entity).to[String].map { responseBody =>
        FetchResponse(
          status = response.status.intValue(),
          contentType = response.entity.contentType.toString(),
          body = responseBody,
          success = response.status.isSuccess(),
          error = None
        )
      }
    }.recover {
      case ex: Exception =>
        FetchResponse(
          status = 0,
          contentType = "",
          body = "",
          success = false,
          error = Some(ex.getMessage)
        )
    }
  }

  val route =
    concat(
      // Health check endpoint
      path("health") {
        get {
          complete(StatusCodes.OK, """{"status": "ok"}""")
        }
      },
      // Single URL fetch
      path("fetch") {
        post {
          entity(as[FetchRequest]) { fetchRequest =>
            val responseFuture = fetchUrl(fetchRequest)
            onComplete(responseFuture) {
              case Success(fetchResponse) =>
                complete(StatusCodes.OK, fetchResponse)
              case Failure(ex) =>
                complete(StatusCodes.InternalServerError,
                  FetchResponse(0, "", "", success = false, error = Some(ex.getMessage)))
            }
          }
        }
      },
      // Batch URL fetch
      path("fetch" / "batch") {
        post {
          entity(as[List[FetchRequest]]) { fetchRequests =>
            val responsesFuture = Future.sequence(fetchRequests.map(fetchUrl))
            onComplete(responsesFuture) {
              case Success(responses) =>
                complete(StatusCodes.OK, responses)
              case Failure(ex) =>
                complete(StatusCodes.InternalServerError,
                  JsObject("error" -> JsString(ex.getMessage)))
            }
          }
        }
      },
      // Simple URL fetch via query parameter
      path("proxy") {
        get {
          parameter("url") { url =>
            val responseFuture = fetchUrl(FetchRequest(url, None, None, None))
            onComplete(responseFuture) {
              case Success(fetchResponse) =>
                complete(StatusCodes.OK, fetchResponse)
              case Failure(ex) =>
                complete(StatusCodes.InternalServerError,
                  FetchResponse(0, "", "", success = false, error = Some(ex.getMessage)))
            }
          }
        }
      },
      // Forward/webhook endpoint - forwards the incoming request body to the target URL
      path("webhook" / "forward") {
        post {
          entity(as[JsValue]) { json =>
            val fields = json.asJsObject.fields
            val targetUrl = fields("target_url").convertTo[String]
            val payload = fields.get("payload").map(_.compactPrint).getOrElse("{}")
            val webhookHeaders = fields.get("headers").map(_.convertTo[Map[String, String]]).getOrElse(Map.empty)

            val fetchRequest = FetchRequest(
              url = targetUrl,
              method = Some("POST"),
              headers = Some(webhookHeaders + ("Content-Type" -> "application/json")),
              body = Some(payload)
            )

            val responseFuture = fetchUrl(fetchRequest)
            onComplete(responseFuture) {
              case Success(fetchResponse) =>
                complete(StatusCodes.OK, fetchResponse)
              case Failure(ex) =>
                complete(StatusCodes.InternalServerError,
                  FetchResponse(0, "", "", success = false, error = Some(ex.getMessage)))
            }
          }
        }
      }
    )

  val bindingFuture = Http().newServerAt("0.0.0.0", 8080).bind(route)

  bindingFuture.onComplete {
    case Success(binding) =>
      val address = binding.localAddress
      println(s"Webhook Proxy Service running at http://${address.getHostString}:${address.getPort}/")
    case Failure(ex) =>
      println(s"Failed to bind HTTP server: ${ex.getMessage}")
      system.terminate()
  }
}